import{_ as e,o as i,c as o,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Manual de Clean Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/01-introduccion-y-principios.md","filePath":"full-stack/arquitectura/clean-architecture/01-introduccion-y-principios.md","lastUpdated":1782521464000}'),s={name:"full-stack/arquitectura/clean-architecture/01-introduccion-y-principios.md"};function t(r,a,l,c,d,p){return i(),o("div",null,[...a[0]||(a[0]=[n(`<h1 id="manual-de-clean-architecture" tabindex="-1">Manual de Clean Architecture <a class="header-anchor" href="#manual-de-clean-architecture" aria-label="Permalink to &quot;Manual de Clean Architecture&quot;">​</a></h1><p>Clean Architecture es una forma de organizar software para que las reglas de negocio no dependan de frameworks, bases de datos, interfaces graficas ni servicios externos.</p><p>El objetivo no es llenar el proyecto de carpetas, sino proteger lo importante: casos de uso, entidades, reglas de negocio y decisiones que cambian menos que la tecnologia usada alrededor.</p><h2 id="capitulos-previstos" tabindex="-1">Capitulos previstos <a class="header-anchor" href="#capitulos-previstos" aria-label="Permalink to &quot;Capitulos previstos&quot;">​</a></h2><ol><li><a href="./01-introduccion-y-principios">Introduccion y principios</a></li><li><a href="./02-capas-y-reglas-de-dependencia">Capas y reglas de dependencia</a></li><li><a href="./03-entidades-casos-de-uso-y-adaptadores">Entidades casos de uso y adaptadores</a></li><li><a href="./04-aplicacion-en-backend">Aplicacion en backend</a></li><li><a href="./05-testing">Testing</a></li><li><a href="./06-errores-comunes">Errores comunes</a></li><li><a href="./07-decisiones-arquitectonicas-y-trade-offs">Decisiones arquitectonicas y trade-offs</a></li><li><a href="./08-fronteras-modulos-y-paquetes">Fronteras modulos y paquetes</a></li><li><a href="./09-integracion-con-ddd-y-hexagonal">Integracion con DDD y arquitectura hexagonal</a></li><li><a href="./10-observabilidad-y-operacion">Observabilidad y operacion</a></li><li><a href="./11-refactorizacion-hacia-clean-architecture">Refactorizacion hacia Clean Architecture</a></li><li><a href="./12-proyecto-final">Proyecto final</a></li></ol><h2 id="idea-principal" tabindex="-1">Idea principal <a class="header-anchor" href="#idea-principal" aria-label="Permalink to &quot;Idea principal&quot;">​</a></h2><p>La regla mas importante es la regla de dependencia:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Frameworks y drivers</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>Adaptadores</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>Casos de uso</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>Dominio</span></span></code></pre></div><p>Las dependencias apuntan hacia dentro. El dominio no conoce Express, Django, Spring, React, PostgreSQL ni Kafka. La infraestructura conoce al dominio porque lo implementa, lo persiste o lo expone.</p><h2 id="cuando-aporta-valor" tabindex="-1">Cuando aporta valor <a class="header-anchor" href="#cuando-aporta-valor" aria-label="Permalink to &quot;Cuando aporta valor&quot;">​</a></h2><ul><li>Aplicaciones con reglas de negocio que van a crecer.</li><li>Equipos donde frontend, backend, datos y producto cambian a ritmos distintos.</li><li>Sistemas con varias interfaces: API REST, jobs, CLI, eventos o panel administrativo.</li><li>Proyectos donde el framework no debe dictar todas las decisiones.</li><li>Codigo que necesita pruebas rapidas sin levantar base de datos ni servidor.</li></ul><h2 id="cuando-puede-ser-excesiva" tabindex="-1">Cuando puede ser excesiva <a class="header-anchor" href="#cuando-puede-ser-excesiva" aria-label="Permalink to &quot;Cuando puede ser excesiva&quot;">​</a></h2><ul><li>Scripts muy pequenos.</li><li>CRUDs internos con vida corta.</li><li>Prototipos donde el objetivo es validar una idea en horas.</li><li>Equipos que todavia no dominan bien el lenguaje o framework base.</li></ul><h2 id="principios-clave" tabindex="-1">Principios clave <a class="header-anchor" href="#principios-clave" aria-label="Permalink to &quot;Principios clave&quot;">​</a></h2><ul><li>El dominio debe ser independiente.</li><li>Los casos de uso coordinan acciones, no almacenan detalles tecnicos.</li><li>Los adaptadores traducen entre el exterior y el modelo interno.</li><li>La infraestructura se cambia mas facil cuando esta detras de interfaces.</li><li>Los tests deben poder ejecutar reglas importantes sin arrancar todo el sistema.</li></ul><h2 id="ejemplo-mental" tabindex="-1">Ejemplo mental <a class="header-anchor" href="#ejemplo-mental" aria-label="Permalink to &quot;Ejemplo mental&quot;">​</a></h2><p>En vez de pensar:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Controller -&gt; ORM -&gt; tabla</span></span></code></pre></div><p>Piensa:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Controller -&gt; caso de uso -&gt; puerto -&gt; repositorio concreto -&gt; base de datos</span></span></code></pre></div><p>El controlador no decide la regla de negocio. El ORM no define el modelo del negocio. La base de datos es importante, pero no manda sobre el corazon de la aplicacion.</p>`,21)])])}const m=e(s,[["render",t]]);export{h as __pageData,m as default};
